sql:
SELECT crypto_id
FROM mining_performance
WHERE profitability > (SELECT AVG(profitability) FROM mining_performance);

SELECT crypto_id, COUNT(DISTINCT user_id) AS total_alert_users
FROM alerts
GROUP BY crypto_id;

SELECT AVG(hashrate) AS average_hashrate
FROM mining_performance
WHERE hashrate > 10;

SELECT COUNT(forum_id) AS total_forums
FROM community_forums
WHERE user_id = 112;

external_knowledge:
- "navigators" metaphorically refers to users who are actively involved in financial activities;
- "ship names" symbolizes usernames;
- "charted their course through the seas of investment" implies having an investment portfolio;
- "set their compasses for receiving storm warnings" indicates having alerts set up.

sql:
SELECT name, withdrawal_limits, fees
FROM exchanges
ORDER BY withdrawal_limits DESC, fees ASC;

SELECT crypto_id, COUNT(user_id) AS miner_count
FROM mining_rigs
GROUP BY crypto_id;

SELECT crypto_id
FROM mining_performance
WHERE profitability = (
  SELECT MAX(profitability) FROM mining_performance
)
LIMIT 1;

SELECT rig_id, power_consumption, fan_speed
FROM mining_rigs
WHERE power_consumption > 1000 AND fan_speed < 500;

SELECT crypto_id, hashrate, profitability
FROM mining_performance
WHERE temperature > 80;

SELECT SUM(amount_invested)
FROM investment_portfolios
WHERE amount_invested > 10000;

SELECT hashrate
FROM mining_performance
WHERE difficulty > (SELECT AVG(difficulty) FROM mining_performance);

SELECT COUNT(*)
FROM community_forum_comments
WHERE user_id = 'user_id_here';

external_knowledge:
- "bustling marketplaces" refers to exchanges that are active and support multiple cryptocurrencies;
- "ventured into supporting over a dozen digital treasures" means exchanges that support more than 10 cryptocurrencies;
- "combined wealth exceeds the billion-dollar mark" indicates that the sum of market capitalizations for these cryptocurrencies is over 10 billion.

